-- Migraci¾n 006: agrega placas a herramientas + foto_poliza_seguro a revision_auto

ALTER TABLE herramientas
  ADD COLUMN IF NOT EXISTS placas VARCHAR(20);

ALTER TABLE revision_auto
  ADD COLUMN IF NOT EXISTS foto_poliza_seguro TEXT;

